import re

def check(stdout: str) -> bool:
    def find_val(name):
        pattern = r'(?i)\b' + re.escape(name) + r'\s*=\s*(-?\d+\.?\d*(?:[eE][-+]?\d+)?)'
        m = re.search(pattern, stdout)
        if m is None:
            return None
        try:
            return float(m.group(1))
        except ValueError:
            return None

    iout_p9   = find_val('iout_p9')
    rout      = find_val('rout')
    match_err = find_val('match_err')
    comp_err  = find_val('comp_err')

    if any(v is None for v in (iout_p9, rout, match_err, comp_err)):
        return False

    # Spec 1: DC matching within +/-1% at Vout = 0.9 V
    if abs(match_err) >= 0.01:
        return False
    # Spec 2: output resistance >= 500 kOhm at Vout = 0.9 V
    if rout < 500e3:
        return False
    # Spec 3: low-compliance accuracy, |Iout(0.4)-Iout(0.9)|/Iout(0.9) < 2%
    if abs(comp_err) >= 0.02:
        return False
    # Spec 4: nominal Iout is in the right ballpark (sanity, ~100 uA)
    if not (90e-6 < iout_p9 < 110e-6):
        return False

    return True

