def check(stdout: str) -> bool:
    def grab(name):
        m = re.search(r'\b' + re.escape(name) + r'\s*=\s*([-+]?\d+\.?\d*(?:[eE][-+]?\d+)?)', stdout)
        if m is None:
            return None
        try:
            return float(m.group(1))
        except ValueError:
            return None

    vout_avg   = grab('vout_avg')
    ripple_v   = grab('ripple_v')
    efficiency = grab('efficiency')
    settle_err = grab('settle_err')

    vals = (vout_avg, ripple_v, efficiency, settle_err)
    if any(v is None for v in vals):
        return False

    # Headline regulation: 5 V +/- 5%
    if not (4.75 <= vout_avg <= 5.25):
        return False
    # Output ripple: peak-to-peak below 100 mV
    if not (0.0 <= ripple_v <= 0.10):
        return False
    # Conversion efficiency above 80%
    if not (efficiency >= 0.80):
        return False
    # Settled by t = 1.5 ms (within 100 mV of steady-state average)
    if not (abs(settle_err) <= 0.10):
        return False
    return True

