def check(stdout: str) -> bool:
    num = r'([-+]?\d+\.?\d*(?:[eE][-+]?\d+)?)'
    pass_count = 0
    for i in range(1, 10):
        vals = {}
        for name in ('dcgain', 'fcgain', 'sbgain', 'phfc'):
            pat = rf'{name}_c{i}\s*=\s*{num}'
            m = re.search(pat, stdout)
            if not m:
                vals = None
                break
            try:
                vals[name] = float(m.group(1))
            except ValueError:
                vals = None
                break
        if vals is None:
            continue
        dc = vals['dcgain']
        fc = vals['fcgain']
        sb = vals['sbgain']
        ph = vals['phfc']
        # Normalize phase if reported in radians (|ph| < 2*pi)
        if -7.0 < ph < 7.0:
            ph = ph * 180.0 / 3.141592653589793
        # Wrap phase into [-180, 180] just in case
        while ph > 180.0:
            ph -= 360.0
        while ph < -180.0:
            ph += 360.0
        ok_dc = 5.5 <= dc <= 6.5
        ok_fc = 2.0 <= fc <= 4.0
        ok_sb = sb <= -30.0
        ok_ph = -110.0 <= ph <= -70.0
        if ok_dc and ok_fc and ok_sb and ok_ph:
            pass_count += 1
    return pass_count >= 8

