def check(stdout: str) -> bool:
    blocks = re.findall(
        r"BEGIN_CORNER\s+vsupply=(\S+)\s+tamb=(\S+)(.*?)END_CORNER",
        stdout, re.DOTALL)
    if len(blocks) < 9:
        return False
    num = r"([-+]?\d+\.?\d*(?:[eE][-+]?\d+)?)"
    pass_count = 0
    total = 0
    for vs, ta, body in blocks:
        total += 1
        vref = iq = pdc = p1k = p1m = None
        for line in body.split("\n"):
            ls = line.strip()
            if ls.startswith("OP_RESULT"):
                mv = re.search(r"vref\s*=\s*" + num, ls)
                mi = re.search(r"iq\s*=\s*" + num, ls)
                if mv:
                    try: vref = float(mv.group(1))
                    except ValueError: pass
                if mi:
                    try: iq = float(mi.group(1))
                    except ValueError: pass
            elif ls.startswith("AC_RESULT"):
                md = re.search(r"psrr_dc\s*=\s*" + num, ls)
                m1 = re.search(r"psrr_1k\s*=\s*" + num, ls)
                m2 = re.search(r"psrr_1m\s*=\s*" + num, ls)
                if md:
                    try: pdc = float(md.group(1))
                    except ValueError: pass
                if m1:
                    try: p1k = float(m1.group(1))
                    except ValueError: pass
                if m2:
                    try: p1m = float(m2.group(1))
                    except ValueError: pass
        if None in (vref, iq, pdc, p1k, p1m):
            continue
        ok_vref = 1.2425 <= vref <= 1.2575
        ok_iq   = 0.0 <= iq <= 200e-6
        ok_pdc  = pdc >= 50.0
        ok_p1k  = p1k >= 45.0
        ok_p1m  = p1m >= 20.0
        if ok_vref and ok_iq and ok_pdc and ok_p1k and ok_p1m:
            pass_count += 1
    if total == 0:
        return False
    return (pass_count / total) >= 0.8

