    matches = pattern.findall(stdout)
    if len(matches) < 9:
        # fallback: try to parse from meas printouts
        # look for vavg_ss, ripple_ss, undershoot, eff lines
        vavgs = re.findall(r'vavg_ss\s*=\s*([0-9.eE+-]+)', stdout)
