        unders = re.findall(r'undershoot\s*=\s*([0-9.eE+-]+)', stdout)
        effs = re.findall(r'eff\s*=\s*([0-9.eE+-]+)', stdout)
        n = min(len(vavgs), len(ripples), len(unders), len(effs))
        if n < 9:
            return False
        passed = 0
        for i in range(9):
            try:
                v = float(vavgs[i]); r = float(ripples[i]); u = float(unders[i]); e = float(effs[i])
            except Exception:
                continue
            ok = (3.15 <= v <= 3.45) and (r <= 0.080) and (u <= 0.250) and (e >= 0.80)
            if ok:
                passed += 1
        return passed >= 7  # relaxed fallback
    passed = 0
    for m in matches:
        try:
            vdd = float(m[0]); t = float(m[1]); v = float(m[2]); r = float(m[3]); u = float(m[4]); e = float(m[5])
        except Exception:
            continue
        ok = (3.10 <= v <= 3.50) and (r <= 0.100) and (u <= 0.300) and (e >= 0.75)
        if ok:
            passed += 1
    return passed >= 7

