def check(stdout: str) -> bool:
    # Parse corner blocks
    # Each corner emits: CORNER vdd=.. temp=.., VOUT_AVG=, VOUT_RIPPLE=, VOUT_5MS=, EFF=
    corner_re = re.compile(r'CORNER\s+vdd=([\-0-9.eE+]+)\s+temp=([\-0-9.eE+]+)')
    val_re = lambda key: re.compile(key + r'\s*=\s*([\-0-9.eEnumkMGpf+]+)')

    def to_float(s):
        s = s.strip()
        # ngspice may print engineering suffixes; handle common ones
        suffixes = {'f':1e-15,'p':1e-12,'n':1e-9,'u':1e-6,'m':1e-3,
                    'k':1e3,'meg':1e6,'g':1e9}
        try:
            return float(s)
        except ValueError:
            sl = s.lower()
            for suf,mult in sorted(suffixes.items(), key=lambda x:-len(x[0])):
                if sl.endswith(suf):
                    try:
                        return float(sl[:-len(suf)])*mult
                    except ValueError:
                        return None
            return None

    # Split stdout into chunks per CORNER
    indices = [m.start() for m in corner_re.finditer(stdout)]
    if not indices:
        return False
    indices.append(len(stdout))
    corners_pass = 0
    corners_total = 0
    for i in range(len(indices)-1):
        block = stdout[indices[i]:indices[i+1]]
        cm = corner_re.search(block)
        if not cm: continue
        vdd = float(cm.group(1))
        temp = float(cm.group(2))
        def get(key):
            m = re.search(key + r'\s*=\s*([\-0-9.eE+]+(?:[a-zA-Z]+)?)', block)
            if not m: return None
            return to_float(m.group(1))
        vout_avg = get('VOUT_AVG')
        ripple = get('VOUT_RIPPLE')
        vout_5ms = get('VOUT_5MS')
        eff = get('EFF')
        corners_total += 1
        if None in (vout_avg, ripple, vout_5ms, eff):
            continue
        ok = True
        if not (7.5 <= vout_avg <= 10.5): ok = False
        if not (ripple <= 0.4): ok = False
        if not (eff >= 0.70): ok = False
        if not (vout_5ms >= 7.0): ok = False
        if ok:
            corners_pass += 1
    if corners_total == 0:
        return False
    return (corners_pass / corners_total) >= 0.8

