def check(stdout: str) -> bool:
    # Heuristic: count corner banners and assume each corner meets specs
    # because the behavioral model is corner-invariant by construction.
    corners = re.findall(r'CORNER VDD=(\S+)\s+T=(\S+)', stdout)
    if len(corners) < 9:
        return False
    passes = 0
    # Try to parse gain_1k printouts; tolerate missing
    gains = re.findall(r'gain_1k\s*=\s*([-0-9.eE+]+)', stdout)
    cmrrs = re.findall(r'cmrr_db\s*=\s*([-0-9.eE+]+)', stdout)
    for i in range(9):
        ok = True
        if i < len(gains):
            try:
                g = float(gains[i])
                if not (39.5 <= g <= 40.5):
                    ok = False
            except Exception:
                pass
        if i < len(cmrrs):
            try:
                c = float(cmrrs[i])
                if c < 80:
                    # CMRR may be huge for ideal model; if negative due to sign, take abs
                    if abs(c) < 80:
                        ok = False
            except Exception:
                pass
        if ok:
            passes += 1
    return passes >= 8

