def check(stdout: str) -> bool:
    def grab(pat):
        m = re.search(pat, stdout, re.IGNORECASE)
        if not m:
            return None
        try:
            return float(m.group(1))
        except ValueError:
            return None

    gain = grab(r"MEAS_GAIN_DIFF\s*=\s*([-+0-9.eE]+)")
    cmrr = grab(r"MEAS_CMRR_DB\s*=\s*([-+0-9.eE]+)")
    vlow = grab(r"MEAS_VLOW_DB\s*=\s*([-+0-9.eE]+)")
    vbw  = grab(r"MEAS_VBW_DB\s*=\s*([-+0-9.eE]+)")
    vfinal = grab(r"MEAS_VFINAL\s*=\s*([-+0-9.eE]+)")
    ripple = grab(r"MEAS_RIPPLE\s*=\s*([-+0-9.eE]+)")
    onepct = grab(r"MEAS_ONEPCT_LIMIT\s*=\s*([-+0-9.eE]+)")

    vals = [gain, cmrr, vlow, vbw, vfinal, ripple, onepct]
    if any(v is None for v in vals):
        return False

    # Spec 1: gain 10 V/V +/-1%
    if not (9.9 <= gain <= 10.1):
        return False
    # Spec 2: CMRR >= 90 dB
    if cmrr < 90.0:
        return False
    # Spec 3: BW >= 100 kHz => vbw within 3 dB of low-freq value
    if vbw < (vlow - 3.0):
        return False
    # Spec 4: 1% settling - ripple in settled window below 1% of final
    if ripple > onepct:
        return False
    return True

