def check(stdout: str) -> bool:
    def grab(pat):
        m = re.search(pat, stdout, re.IGNORECASE)
        if not m:
            return None
        try:
            return float(m.group(1))
        except:
            return None

    gain_10k = grab(r'gain_10k\s*=\s*([-\d.eE+]+)')
    bw = grab(r'bw_hz\s*=\s*([-\d.eE+]+)')
    isup = grab(r'isup\s*=\s*([-\d.eE+]+)')
    tlast = grab(r'tlast_out\s*=\s*([-\d.eE+]+)')

    if gain_10k is None or bw is None or isup is None:
        return False

    # Gain: 100 kV/A => 100 dBOhm. Allow +/-1% of linear => ~+/-0.086 dB
    if not (99.91 <= gain_10k <= 100.09):
        return False
    if bw < 800e3:
        return False
    if abs(isup) > 2e-3:
        return False
    # settling time from step at 200ns: tlast - 200ns < 1.5us
    if tlast is None:
        return False
    if (tlast - 200e-9) > 1.5e-6:
        return False
    return True

